function generateCase42(schemas) {
  const requiredFields = [];
  for (const [obj, fields] of Object.entries(schemas)) {
    for (const f of fields) {
      if (f.required && f.id !== 'id' && !['created_at', 'updated_at', 'created_by', 'updated_by'].includes(f.id)) {
        requiredFields.push({ obj, field: f.id });
      }
    }
  }
  return `
// ============================================================
// case 42: 必填字段缺失
// 模型源: fields[].required=true
// ============================================================
test.describe('case 42: 必填字段缺失', () => {
${requiredFields.slice(0, 5).map(({ obj, field }) => `  test('${obj} 缺 ${field} 应 422', async ({ page }) => {
    await loginAs(page, 'TEST333');
    const data = { name: 'no_${field}' };
    // 故意不带 ${field}
    if ('code' !== '${field}') data.code = 'TMP';
    delete data.${field};
    const r = await page.request.post(\`\${API_BASE}/api/v1/${obj}\`, {
      headers: { 'X-User-Id': 'TEST333' },
      data,
    });
    expect([200, 201, 400, 422]).toContain(r.status());
  });
`).join('\n')}
});

`;
}

